const body = $input.item.json.body || $input.item.json;
const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
let id = 'MR-';
for(let i=0;i<8;i++) id += chars[Math.floor(Math.random()*chars.length)];
return {
  unit: body.unit || '',
  tenant_name: body.tenant_name || '',
  tenant_email: body.tenant_email || '',
  issue_description: body.issue_description || '',
  stated_urgency: body.urgency || 'unknown',
  received_at: new Date().toISOString(),
  ticket_id: id
};

const axios = require('axios');
const item = $input.item.json;

const prompt = `You are a maintenance triage AI for a property management company.
Classify this request:
Unit: ${item.unit}
Tenant: ${item.tenant_name}
Issue: ${item.issue_description}
Stated urgency: ${item.stated_urgency}

Reply ONLY with valid JSON, no markdown:
{"urgency":"routine|urgent|emergency","category":"plumbing|hvac|electrical|structural|cosmetic|appliance|pest|other","reasoning":"one sentence","vendor_category":"plumbing|hvac|electrical|general|emergency"}`;

const res = await axios.post('https://openrouter.ai/api/v1/chat/completions', {
  model: 'anthropic/claude-haiku-4-5',
  max_tokens: 256,
  messages: [{ role: 'user', content: prompt }]
}, {
  headers: {
    'Authorization': 'Bearer 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',
    'Content-Type': 'application/json'
  }
});

let parsed;
try {
  let text = res.data.choices[0].message.content.trim();
  text = text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  parsed = JSON.parse(text);
} catch(e) {
  parsed = { urgency: 'routine', category: 'other', reasoning: 'parse error: ' + e.message, vendor_category: 'general' };
}
return { ...item, ...parsed };

const item = $input.item.json;
const cat = item.vendor_category || 'general';
const vendors = {
  plumbing:   { name: 'Demo Plumbing Co',    email: 'jtsomwaru+demo+plumbing@gmail.com',  phone: '555-0101' },
  hvac:       { name: 'Demo HVAC Services',  email: 'jtsomwaru+demo+hvac@gmail.com',      phone: '555-0102' },
  electrical: { name: 'Demo Electric Inc',   email: 'jtsomwaru+demo+electric@gmail.com',  phone: '555-0103' },
  emergency:  { name: 'Demo Emergency 24/7', email: 'jtsomwaru+demo+emergency@gmail.com', phone: '555-0199' },
  general:    { name: 'Demo General Works',  email: 'jtsomwaru+demo+general@gmail.com',   phone: '555-0100' }
};
const sla = { routine: '72 hours', urgent: '24 hours', emergency: '2 hours' };
const vendor = vendors[cat] || vendors.general;
return { ...item, vendor_assigned: vendor, sla_window: sla[item.urgency] || '72 hours' };

const item = $input.item.json;
return {
  ticket_id: item.ticket_id,
  status: 'dispatched',
  unit: item.unit,
  tenant_name: item.tenant_name,
  classification: { urgency: item.urgency, category: item.category, reasoning: item.reasoning },
  vendor_assigned: item.vendor_assigned,
  sla_window: item.sla_window,
  emergency_alert_sent: item.urgency === 'emergency',
  received_at: item.received_at
};
